using sv_517595144a69462aa04a11f53a6f4379.Client.Services;

namespace sv_517595144a69462aa04a11f53a6f4379.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTime(2026, 5, 28, 17, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "New York, NY", Timestamp = new DateTime(2026, 5, 22, 9, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Departed facility", Location = "New York, NY", Timestamp = new DateTime(2026, 5, 22, 14, 30, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Arrived at sorting center", Location = "Chicago, IL", Timestamp = new DateTime(2026, 5, 24, 6, 15, 0, DateTimeKind.Utc) },
            ]
        },
        ["TRK-002"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTime(2026, 5, 20, 12, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = new DateTime(2026, 5, 17, 8, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = new DateTime(2026, 5, 18, 11, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 20, 7, 30, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 20, 11, 45, 0, DateTimeKind.Utc) },
            ]
        },
        ["TRK-003"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTime(2026, 6, 1, 18, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = new DateTime(2026, 5, 25, 10, 0, 0, DateTimeKind.Utc) },
            ]
        },
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment '{trackingNumber}' not found.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@implements IAsyncDisposable
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (error is not null)
{
    <div class="alert alert-danger">
        <p>@error</p>
        <button class="btn btn-outline-danger" @onclick="LoadAsync">Retry</button>
    </div>
}
else if (shipment is null)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment @TrackingNumber…</em></p>
    </div>
}
else
{
    @if (isLoading)
    {
        <p><em>Refreshing…</em></p>
    }

    <h2>Shipment @shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@shipment.Status</dd>
        <dt>Location</dt>
        <dd>@shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Tracking History</h3>
    @if (shipment.StatusUpdates.Count == 0)
    {
        <p>No updates yet.</p>
    }
    else
    {
        <ul>
            @foreach (var update in shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
            {
                <li>
                    <strong>@update.Timestamp.ToString("g")</strong> — @update.Description (@update.Location)
                </li>
            }
        </ul>
    }
}

@code {
    [Parameter] public string TrackingNumber { get; set; } = default!;

    private CancellationTokenSource? cts;
    private string? loadedTrackingNumber;
    private ShipmentDetails? shipment;
    private bool isLoading;
    private string? error;

    protected override async Task OnParametersSetAsync()
    {
        if (string.Equals(TrackingNumber, loadedTrackingNumber, StringComparison.OrdinalIgnoreCase))
        {
            return;
        }

        loadedTrackingNumber = TrackingNumber;
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        if (cts is not null)
        {
            await cts.CancelAsync();
            cts.Dispose();
        }

        cts = new CancellationTokenSource();
        var cancellationToken = cts.Token;

        error = null;
        isLoading = true;

        try
        {
            var result = await ShipmentService.GetShipmentAsync(TrackingNumber, cancellationToken);
            shipment = result;
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // Self-cancellation (parameter change or disposal) — do nothing.
        }
        catch (OperationCanceledException ex) when (!cancellationToken.IsCancellationRequested)
        {
            Logger.LogWarning(ex, "Request timed out for shipment {TrackingNumber}", TrackingNumber);
            error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load shipment {TrackingNumber}", TrackingNumber);
            error = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (cts is not null)
        {
            await cts.CancelAsync();
            cts.Dispose();
        }
    }
}

